  // Export PDF was printing whatever happened to already be expanded on
  // screen — since sections are collapsed by default and there's no
  // Expand all button anymore, that usually meant an empty-looking PDF
  // (chapter titles/progress counts only, no data). Force every section
  // open first and wait for that render before printing.
  template = template.replace(
    "  exportPDF() {\n    this.setState({ menuOpen: false });\n    if (window.electronPrint) {\n      window.electronPrint.exportPDF(this.currentLabel + \".pdf\").then((res) => {\n        this.flashStatus(res && res.ok ? \"PDF saved\" : \"PDF export cancelled\");\n      }).catch((err) => {\n        console.error(\"[exportPDF] failed:\", err);\n        this.flashStatus(\"PDF export failed — see console\");\n      });\n      return;\n    }\n    setTimeout(() => window.print(), 50);\n  }",
    "  exportPDF() {\n    // Sections are collapsed by default and there's no \"Expand all\" button\n    // anymore — printing/PDF-ing without expanding first only captures\n    // whatever happens to already be open on screen (chapter titles and\n    // progress counts, no actual data), which is what got reported. Force\n    // everything open first, matching what the old Expand all button did,\n    // then wait for that render before printing.\n    const openChapters = {};\n    CHAPTERS.forEach(c => openChapters[c.key] = true);\n    this.setState({ menuOpen: false, openChapters, qualOpen: true, mistakeOpen: true, dailyOpen: true }, () => {\n      setTimeout(() => {\n        if (window.electronPrint) {\n          window.electronPrint.exportPDF(this.currentLabel + \".pdf\").then((res) => {\n            this.flashStatus(res && res.ok ? \"PDF saved\" : \"PDF export cancelled\");\n          }).catch((err) => {\n            console.error(\"[exportPDF] failed:\", err);\n            this.flashStatus(\"PDF export failed — see console\");\n          });\n          return;\n        }\n        window.print();\n      }, 80);\n    });\n  }\n"
  );

