  template = template.replace(
    "    <div style=\"display:flex;align-items:center;gap:6px;flex-shrink:0;\">\n      <label style=\"font-size:11px;color:#7d7047;text-transform:uppercase;letter-spacing:0.5px;\">Month</label>\n      <sc-raw-select value=\"{{ month }}\" sc-camel-on-change=\"{{ onMonthChange }}\" style=\"padding:6px 8px;border-radius:6px;border:none;font-size:13px;font-family:'JetBrains Mono',monospace;\">\n        <sc-for list=\"{{ monthOptions }}\" as=\"m\" hint-placeholder-count=\"12\">\n          <option value=\"{{ m.value }}\">{{ m.label }}</option>\n        </sc-for>\n      </sc-raw-select>\n    </div>\n    <div style=\"display:flex;align-items:center;gap:6px;flex-shrink:0;\">\n      <label style=\"font-size:11px;color:#7d7047;text-transform:uppercase;letter-spacing:0.5px;\">Year</label>\n      <sc-raw-select value=\"{{ year }}\" sc-camel-on-change=\"{{ onYearChange }}\" style=\"padding:6px 8px;border-radius:6px;border:none;font-size:13px;font-family:'JetBrains Mono',monospace;\">\n        <sc-for list=\"{{ yearOptions }}\" as=\"y\" hint-placeholder-count=\"10\">\n          <option value=\"{{ y.value }}\">{{ y.label }}</option>\n        </sc-for>\n      </sc-raw-select>\n    </div>\n    <span style=\"font-size:12px;color:#2f8f5b;font-family:'JetBrains Mono',monospace;text-align:right;flex-shrink:0;white-space:nowrap;\">{{ saveStatus }}</span>\n    </div>\n",
    "    <div style=\"display:flex;align-items:center;gap:6px;flex-shrink:0;\">\n      <label style=\"font-size:11px;color:#7d7047;text-transform:uppercase;letter-spacing:0.5px;\">Month</label>\n      <sc-raw-select value=\"{{ month }}\" sc-camel-on-change=\"{{ onMonthChange }}\" style=\"padding:6px 8px;border-radius:6px;border:none;font-size:13px;font-family:'JetBrains Mono',monospace;\">\n        <sc-for list=\"{{ monthOptions }}\" as=\"m\" hint-placeholder-count=\"12\">\n          <option value=\"{{ m.value }}\">{{ m.label }}</option>\n        </sc-for>\n      </sc-raw-select>\n    </div>\n    <span style=\"font-size:12px;color:#2f8f5b;font-family:'JetBrains Mono',monospace;text-align:right;flex-shrink:0;white-space:nowrap;\">{{ saveStatus }}</span>\n    </div>\n    <div style=\"position:relative;display:flex;align-items:center;gap:6px;flex-shrink:0;\">\n      <label style=\"font-size:11px;color:#7d7047;text-transform:uppercase;letter-spacing:0.5px;\">Year</label>\n      <button sc-camel-on-click=\"{{ toggleYearPicker }}\" style=\"padding:6px 8px;border-radius:6px;border:none;font-size:13px;font-family:'JetBrains Mono',monospace;background:#fff;color:#10233a;cursor:pointer;min-width:64px;text-align:left;\">{{ year }} ▾</button>\n      <sc-if value=\"{{ yearPickerOpen }}\" hint-placeholder-val=\"{{ false }}\">\n        <div style=\"position:absolute;top:100%;left:0;margin-top:4px;background:#fff;border-radius:8px;box-shadow:0 12px 30px rgba(0,0,0,0.25);max-height:240px;overflow-y:auto;min-width:90px;z-index:1000;\">\n          <sc-for list=\"{{ yearOptions }}\" as=\"y\" hint-placeholder-count=\"10\">\n            <button id=\"year-opt-{{ y.value }}\" sc-camel-on-click=\"{{ y.onSelect }}\" style=\"display:block;width:100%;text-align:left;padding:8px 14px;border:none;background:{{ y.bg }};color:#10233a;font-size:13px;font-family:'JetBrains Mono',monospace;cursor:pointer;\" style-hover=\"background:#f6f3ea;\">{{ y.label }}</button>\n          </sc-for>\n        </div>\n      </sc-if>\n    </div>\n"
  );
