    "      <sc-for list=\"{{ dbList }}\" as=\"item\" hint-placeholder-count=\"3\">\n        <button sc-camel-on-click=\"{{ item.onOpen }}\" style=\"display:block;width:100%;text-align:left;padding:13px 20px;border:none;background:#fff;color:#10233a;font-size:13.5px;font-family:'JetBrains Mono',monospace;cursor:pointer;border-bottom:1px solid #f2f0e6;\" style-hover=\"background:#f6f3ea;\">{{ item.label }}</button>\n      </sc-for>\n    </div>\n  </div>\n</sc-if>\n\n<sc-if value=\"{{ linkModalOpen }}\" hint-placeholder-val=\"{{ false }}\">\n  <div class=\"no-print\" style=\"position:fixed;inset:0;background:rgba(16,35,58,0.55);z-index:60;display:flex;align-items:center;justify-content:center;padding:20px;\">\n    <div style=\"background:#fff;border-radius:12px;max-width:420px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,0.35);\">\n      <div style=\"padding:16px 20px;border-bottom:1px solid #eee;\">\n        <strong style=\"color:#10233a;font-size:15px;\">Paste or edit the link</strong>\n      </div>\n      <div style=\"padding:20px;\">\n        <input type=\"text\" value=\"{{ linkModalValue }}\" sc-camel-on-change=\"{{ onLinkModalChange }}\" placeholder=\"https://...\" style=\"width:100%;box-sizing:border-box;padding:11px 10px;border:1px solid #e4e0d2;border-radius:7px;font-size:14px;font-family:'JetBrains Mono',monospace;background:#fff;\">\n      </div>\n      <div style=\"padding:12px 20px 20px;display:flex;justify-content:flex-end;gap:8px;\">\n        <button sc-camel-on-click=\"{{ cancelLinkModal }}\" style=\"padding:9px 16px;border:1px solid #e4e0d2;background:#fff;color:#10233a;border-radius:6px;font-size:13px;cursor:pointer;\" style-hover=\"background:#f6f3ea;\">Cancel</button>\n        <button sc-camel-on-click=\"{{ saveLinkModal }}\" style=\"padding:9px 16px;border:none;background:#c8963e;color:#10233a;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;\" style-hover=\"background:#d9a94f;\">Save</button>\n      </div>\n    </div>\n  </div>\n</sc-if>\n\n<sc-if value=\"{{ newEntryConfirmOpen }}\" hint-placeholder-val=\"{{ false }}\">\n  <div class=\"no-print\" style=\"position:fixed;inset:0;background:rgba(16,35,58,0.55);z-index:60;display:flex;align-items:center;justify-content:center;padding:20px;\">\n    <div style=\"background:#fff;border-radius:12px;max-width:420px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,0.35);\">\n      <div style=\"padding:20px 20px 0;\">\n        <strong style=\"color:#10233a;font-size:15px;\">Start a new entry?</strong>\n        <p style=\"color:#5a5544;font-size:13.5px;line-height:1.5;margin:10px 0 0;\">This clears everything currently on screen. Your saved copy of {{ currentLabel }} won't be touched unless you type something new or hit Save.</p>\n      </div>\n      <div style=\"padding:16px 20px 20px;display:flex;justify-content:flex-end;gap:8px;\">\n        <button sc-camel-on-click=\"{{ cancelNewEntry }}\" style=\"padding:9px 16px;border:1px solid #e4e0d2;background:#fff;color:#10233a;border-radius:6px;font-size:13px;cursor:pointer;\" style-hover=\"background:#f6f3ea;\">Cancel</button>\n        <button sc-camel-on-click=\"{{ confirmNewEntry }}\" style=\"padding:9px 16px;border:none;background:#c8963e;color:#10233a;border-radius:6px;font-size:13px;font-weight:700;cursor:pointer;\" style-hover=\"background:#d9a94f;\">Continue</button>\n      </div>\n    </div>\n  </div>\n</sc-if>"
